effect.shader:
float rand(vec2 co)
{
    float a = 719.310;
    float b = 178.233;
    float c = 33758.5453;
    float dt= dot(co.xy ,vec2(a,b));
    float sn= mod(dt,3.14);
    return fract(sin(sn) * c);
}

void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = floor((vec2(acScreenNorm.x,1.0-acScreenNorm.y)*acScreenSize)-acLayerCenter-position)/acLayerSize;
    float c = overshoot; //clampRange? 1.0 : 2.0;
    float t = freeze ? 1.0 : acTime;
    if( mono ) {
        float t = mod(t,2.8)+2.7;
        float r = rand( st*t );
        if( extremes ) r = step(0.5,r);
        r = (r * amount * c) + 1.0 - amount;
        gl_FragColor = vec4(vec3(r),1.0)*texColor;
    } else {
        float tr = mod(t,4.7)+2.87;
        float tg = mod(t,2.8)+1.55;
        float tb = mod(t,3.25)+6.271;
        float r = rand( st*tr );
        float g = rand( st*tg );
        float b = rand( st*tb );
        if( extremes ) r = step(0.5,r);
        if( extremes ) g = step(0.5,g);
        if( extremes ) b = step(0.5,b);
        r = (r * amount * c) + 1.0 - amount;
        g = (g * amount * c) + 1.0 - amount;
        b = (b * amount * c) + 1.0 - amount;
        gl_FragColor = vec4(vec3(r,g,b),1.0)*texColor;
    }
}
